/**
 * @param {number[]} nums
 * @param {number} target
 * @return {number}
 */
var countMajoritySubarrays = function(nums, target) {
    const n = nums.length;
    let res = 0;

    for (let i = 0; i < n; i++) {
        let count = 0;

        for (let j = i; j < n; j++) {
            if (nums[j] === target) count++;
            if (count * 2 > j - i + 1) res++;
        }
    }

    return res;
};
